import sys

def solve(data: str) -> str:
    stats: dict[str, list[int]] = {}
    for line in data.splitlines():
        if not line.strip():
            continue
        group, truth, predicted = line.split(','); truth_i = int(truth); pred_i = int(predicted)
        values = stats.setdefault(group, [0,0])
        if truth_i == 1:
            values[1] += 1
            if pred_i == 1:
                values[0] += 1
    rates = {group: (tp/positive if positive else None) for group,(tp,positive) in stats.items()}
    available = [rate for rate in rates.values() if rate is not None]
    parts = [f"{group}={'NA' if rates[group] is None else f'{rates[group]:.3f}'}" for group in sorted(rates)]
    gap = max(available)-min(available) if available else 0.0
    return ' '.join(parts) + f" gap={gap:.3f}"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
